SELECT dump_id, TO_CHAR(tbox_date, 'YYYY-MM-DD') AS tbox_date, user_id, dump_title, dump_content, goal_id, priority_yn, complete_yn, status, reg_id, TO_CHAR(reg_dt, 'YYYY-MM-DD HH24:MI:SS') AS reg_dt, upd_id, TO_CHAR(mod_dt, 'YYYY-MM-DD HH24:MI:SS') AS mod_dt FROM tb_tbox_brain_dump WHERE user_id = #{userId}
AND tbox_date = #{tboxDate}::date
ORDER BY priority_yn DESC, reg_dt ASC

